func runMonitor(args []string) error {
	fs := flag.NewFlagSet("monitor", flag.ContinueOnError)
	fs.SetOutput(os.Stderr)
	since := fs.String("since", "24h", "time window to display (e.g. 1h, 3d, 1w)")
	logsDir := fs.String("logs-dir", "", "path to logs directory (default: <target-dir>/.kiro/logs)")
	targetDirFlag := fs.String("target-dir", ".", "target directory (default: current directory)")
	jsonOut := fs.Bool("json", false, "output DetailedMetrics as JSON instead of launching TUI")
	session := fs.String("session", "", "Narrow output to a single session. Merged view when agent is\n\t\t\t\tnot specified; combine with --agent to narrow to one agent. (requires --json)")
	agent := fs.String("agent", "", "Narrow output to sessions owned by this agent. (requires --json)")
	fs.Usage = func() {
		_, _ = fmt.Fprintf(fs.Output(), "Usage: kapm monitor [flags]\n\n")
		_, _ = fmt.Fprintln(fs.Output(), "Monitor agent activity metrics.")
		fs.PrintDefaults()
	}

	if err := fs.Parse(args); err != nil {
		if errors.Is(err, flag.ErrHelp) {
			return nil
		}
		return err
	}

	if len(fs.Args()) > 0 {
		return fmt.Errorf("monitor does not accept positional arguments")
	}

	if (*session != "" || *agent != "") && !*jsonOut {
		_, _ = fmt.Fprintln(os.Stderr, "error: --session and --agent require --json")
		return fmt.Errorf("--session and --agent require --json")
	}

	targetDir, err := expandTarget(*targetDirFlag)
	if err != nil {
		return err
	}

	resolvedLogsDir := *logsDir
	if resolvedLogsDir == "" {
		resolvedLogsDir = filepath.Join(targetDir, paths.KiroDir, paths.LogsSubdir)
	}

	fileutil.WarnIfKiroSymlink(resolvedLogsDir)

	d, err := monitor.ParseDuration(*since)
	if err != nil {
		return fmt.Errorf("--since: %w", err)
	}

	if *jsonOut {
		return monitor.RunJSON(resolvedLogsDir, d, *session, *agent, os.Stdout)
	}

	return monitor.RunTUI(resolvedLogsDir, d)
}

