func runServe(args []string) error {
	fs := flag.NewFlagSet("serve", flag.ContinueOnError)
	fs.SetOutput(os.Stderr)
	port := fs.Int("port", 9090, "HTTP port")
	open := fs.Bool("open", false, "open browser automatically")
	since := fs.String("since", "24h", "time window (e.g. 1h, 3d, 1w)")
	logsDir := fs.String("logs-dir", "", "path to logs directory (default: <target-dir>/.kiro/logs)")
	targetDirFlag := fs.String("target-dir", ".", "target directory (default: current directory)")
	fs.Usage = func() {
		_, _ = fmt.Fprintf(fs.Output(), "Usage: kapm serve [flags]\n\n")
		_, _ = fmt.Fprintln(fs.Output(), "Serve the kapm WebUI dashboard over HTTP.")
		fs.PrintDefaults()
	}

	if err := fs.Parse(args); err != nil {
		if errors.Is(err, flag.ErrHelp) {
			return nil
		}
		return err
	}
	if len(fs.Args()) > 0 {
		return fmt.Errorf("serve does not accept positional arguments")
	}

	targetDir, err := expandTarget(*targetDirFlag)
	if err != nil {
		return err
	}

	resolvedLogsDir := *logsDir
