// Run converts local and installed APM primitives into .kiro output.
func Run(opts Options) error {
	root := opts.Root
	if root == "" {
		root = "."
	}

	manifest, err := loadManifest(filepath.Join(root, paths.APMManifest))
	if err != nil {
		return fmt.Errorf("load manifest: %w", err)
	}

	sources, err := sourceAPMDirs(root, opts.Force, manifest)
	if err != nil {
		return err
	}

	destination := filepath.Join(root, paths.KiroDir)
	total := convert.Report{}

	for _, src := range sources {
		report, err := runConverters(src, destination, opts.Force, manifest)
		if err != nil {
			return err
		}
		total.Add(report)
	}

	slog.Info("kapm sync complete", "root", root, "sources", len(sources), "converted", total.Converted, "skipped", total.Skipped)
	return nil

// linkRelRenderer adds rel="noopener nofollow" to all <a> tags via goldmark NodeRenderer.
type linkRelRenderer struct{ gmhtml.Config }

func (r *linkRelRenderer) RegisterFuncs(reg renderer.NodeRendererFuncRegisterer) {
	reg.Register(ast.KindLink, r.renderLink)
	reg.Register(ast.KindAutoLink, r.renderAutoLink)
}

func (r *linkRelRenderer) renderAutoLink(w util.BufWriter, source []byte, n ast.Node, entering bool) (ast.WalkStatus, error) {
	if !entering {
		return ast.WalkContinue, nil
	}
	al := n.(*ast.AutoLink)
	u := util.EscapeHTML(util.URLEscape(al.URL(source), false))
	_, _ = w.WriteString(`<a rel="noopener nofollow" href="`)
	_, _ = w.Write(u)
	_, _ = w.WriteString(`">`)
	_, _ = w.Write(util.EscapeHTML(al.Label(source)))
	_, _ = w.WriteString(`</a>`)
	return ast.WalkSkipChildren, nil
}

func (r *linkRelRenderer) renderLink(w util.BufWriter, source []byte, n ast.Node, entering bool) (ast.WalkStatus, error) {
	if !entering {
		_, _ = w.WriteString("</a>")
		return ast.WalkContinue, nil
	}
	link := n.(*ast.Link)
	dest := link.Destination
	// Block javascript: scheme (goldmark's built-in sanitization is bypassed by custom renderer).
	lower := strings.ToLower(strings.TrimSpace(string(dest)))
	if strings.HasPrefix(lower, "javascript:") {
		_, _ = w.WriteString(`<a rel="noopener nofollow" href="#">`)
		return ast.WalkContinue, nil
	}
	_, _ = w.WriteString(`<a rel="noopener nofollow" href="`)
	_, _ = w.Write(util.EscapeHTML(util.URLEscape(dest, true)))
	_, _ = w.WriteString(`">`)
	return ast.WalkContinue, nil

// and returns 0 always. Never writes to stdout. Writes diagnostics to stderr on error.
func Handle(in io.Reader, stdout, stderr io.Writer, now func() time.Time, rootDir, agent string) (exitCode int) {
	defer func() {
		if r := recover(); r != nil {
			_, _ = fmt.Fprintf(stderr, "hook-handler: recovered panic: %v\n", r)
			exitCode = 0
		}
	}()

	limited := io.LimitReader(in, maxHookEvent+1)
	data, err := io.ReadAll(limited)
	if err != nil {
		_, _ = fmt.Fprintf(stderr, "hook-handler: read stdin: %v\n", err)
		return 0
	}
	if int64(len(data)) > maxHookEvent {
		slog.Warn("hook event rejected: too large",
			"size_bytes", len(data),
			"max_bytes", maxHookEvent,
		)
		_, _ = fmt.Fprintf(stderr, "hook-handler: hook event too large (>%d bytes)\n", maxHookEvent)
		return 0
	}

	var ev hookEvent
	if err := json.Unmarshal(data, &ev); err != nil {
		_, _ = fmt.Fprintf(stderr, "hook-handler: parse json: %v\n", err)
		return 0
	}
